#include <iostream>
#include <iomanip>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    // Total numbers: N^2 + (N-1)^2
    int total = N * N + (N - 1) * (N - 1);

    // The rhombus has (2*N - 1) rows and (2*N - 1) columns
    int rows = 2 * N - 1;
    int cols = 2 * N - 1;

    // Fill with 0 (empty)
    vector<vector<int>> grid(rows, vector<int>(cols, 0));

    // We'll fill numbers from total down to 1, starting from the outside
    // The pattern: we have layers from 0 to N-1.
    // Each layer l defines a diamond (rhombus) at the center expanded by l in each direction.
    // For layer l (0-indexed from the smallest center diamond outward):
    // The center is at (N-1, N-1) in (row, col) coordinates (0-indexed).
    // The outer diamond of "radius" l has cells where |r - (N-1)| + |c - (N-1)| <= l
    // But we need to assign numbers, so we start from the outermost and go inward.
    // Actually easier: simulate filling spiral.

    // Let's build the numbers in order from 1 to total.
    // We'll fill the rhombus by walking around the perimeter of increasing diamonds.
    // The shape: for N=4, rows=7, cols=7.
    // We'll generate coordinates of each cell in order 1..total.
    // The path: start from the topmost cell (row 0, col N-1) = 1
    // Then we go down-left, down-right, up-right, up-left, etc.
    // Actually let's think about the pattern:
    // N=4:
    // Row 0: col=3 -> 1
    // Row 1: col=2 -> 12, col=3 -> 13, col=4 -> 2
    // Row 2: col=1 -> 11, col=2 -> 20, col=3 -> 21, col=4 -> 14, col=5 -> 3
    // Row 3: col=0 -> 10, col=1 -> 19, col=2 -> 24, col=3 -> 25, col=4 -> 22, col=5 -> 15, col=6 -> 4
    // Row 4: col=1 -> 9, col=2 -> 18, col=3 -> 23, col=4 -> 16, col=5 -> 5
    // Row 5: col=2 -> 8, col=3 -> 17, col=4 -> 6
    // Row 6: col=3 -> 7

    // This is like a spiral around a diamond.
    // Another way: generate coordinates by walking the perimeter rings from outside to inside.
    // Let's just hardcode the pattern for small N by simulation.
    // We'll fill by "rings". Ring k (0-indexed from center) has cells at distance = k from center.
    // But the numbering goes from outer ring inward.
    // So ring level = N-1 (outermost), N-2, ..., 0 (center cell).

    // Actually let's determine (row, col) for each number from 1 to total.
    // We'll compute the positions.

    // Each "ring" i (0-indexed from outer) has for N:
    // The ring has thickness? Actually a diamond of "radius" r (Manhattan distance from center).
    // For N=4, the center is at (3,3). 
    // The outermost layer has max distance = 3 (the top/bottom/leftmost/rightmost cells from center).
    // Let's approach: generate coordinates in order.

    // We'll work layer by layer from outermost (layer = N-1) down to 0.
    // For a given layer L (max manhattan distance from center):
    // The cells on this layer form a diamond perimeter.
    // We start at the topmost point of this diamond: (center_row - L, center_col)
    // Then go down-right, down-left, up-left, up-right.
    // Actually looking at the pattern:
    // Starting from top point (r,c) = (N-1-L, N-1)
    // Then going:
    // 1. Down-right: (r+1, c+1) repeated L times? Let's check N=4, L=3 (outermost layer):
    // top: (0,3) = 1
    // then: (1,4) = 2? But (1,4) is row1 col4 which is 2. Yes.
    // then: (2,5) = 3
    // then: (3,6) = 4
    // That's going down-right 3 steps (L steps).
    // 2. Then down-left: from (3,6) to (4,5)=5, (5,4)=6, (6,3)=7 -> L steps
    // 3. Then up-left: from (6,3) to (5,2)=8, (4,1)=9, (3,0)=10 -> L steps
    // 4. Then up-right: from (3,0) to (2,1)=11, (1,2)=12, (0,3)=1... wait back to start!
    // Hmm, but 12 is at (1,2) and 11 at (2,1). And up-right from (3,0): (2,1), (1,2), (0,3) but (0,3) is already 1.
    // Actually we should stop before the last step since top point is already filled.
    // So it's L steps for each of first 3 segments, and L-1 steps for the last segment? Let's recount.

    // Outer layer (L=3):
    // Start: (0,3) = 1
    // Segment A (down-right, L steps): (1,4)=2, (2,5)=3, (3,6)=4
    // Segment B (down-left, L steps): (4,5)=5, (5,4)=6, (6,3)=7
    // Segment C (up-left, L steps): (5,2)=8, (4,1)=9, (3,0)=10
    // Segment D (up-right, L-1 steps): (2,1)=11, (1,2)=12  (stop at (0,3) which is start)
    // That gives 1 + 3 + 3 + 3 + 2 = 12 numbers for the outer layer.
    // Total numbers = N^2 + (N-1)^2 = 16+9=25.
    // Inner layers would have L=2, L=1, L=0.

    // Let's verify for N=4:
    // Layer L=3: 12 nums (1..12)
    // Layer L=2: start (1,3). We need to figure out assignments...
    // Actually let's just simulate this properly.

    int center_r = N - 1;
    int center_c = N - 1;

    int num = 1;

    for (int L = N - 1; L >= 0; L--) {
        // Top point of this diamond layer
        int r = center_r - L;
        int c = center_c;

        if (L == 0) {
            // Single center cell
            grid[r][c] = num++;
            break;
        }

        // Place the top point
        grid[r][c] = num++;

        // Segment 1: down-right, L steps
        for (int step = 0; step < L; step++) {
            r++;
            c++;
            grid[r][c] = num++;
        }

        // Segment 2: down-left, L steps
        for (int step = 0; step < L; step++) {
            r++;
            c--;
            grid[r][c] = num++;
        }

        // Segment 3: up-left, L steps
        for (int step = 0; step < L; step++) {
            r--;
            c--;
            grid[r][c] = num++;
        }

        // Segment 4: up-right, L-1 steps (back to top-1)
        for (int step = 0; step < L - 1; step++) {
            r--;
            c++;
            grid[r][c] = num++;
        }
    }

    // Print the grid
    for (int r = 0; r < rows; r++) {
        // Find first non-zero column
        int first = cols;
        int last = -1;
        for (int c = 0; c < cols; c++) {
            if (grid[r][c] != 0) {
                if (first > c) first = c;
                last = c;
            }
        }

        // Print leading spaces to align the first number properly
        // The first number should be positioned such that its setw(3) field starts at the right column.
        // For N=4, row0: first col = 3. Before that we need spaces for columns 0,1,2.
        // Each column takes width 3.
        // So we print '   ' for each empty column before 'first'.
        for (int c = 0; c < first; c++) {
            cout << "   ";
        }

        // Now print the numbers from first to last
        for (int c = first; c <= last; c++) {
            if (grid[r][c] != 0) {
                cout << setw(3) << grid[r][c];
            } else {
                // This shouldn't happen for cells between first and last in a valid rhombus
                cout << "   ";
            }
        }
        cout << "\n";
    }

    return 0;
}
